// Format the market query into a research prompt for the AI
const market = $input.first().json.market || $input.first().json.body?.market || '';

if (!market.trim()) {
  throw new Error('Missing "market" field in request body');
}

return {
  market: market.trim(),
  prompt: `Analyze the SaaS market or product category: "${market.trim()}".\n\nScan for common user complaints, pain points, missing features, and frustrations discussed on Reddit, G2, Capterra, App Store reviews, and Hacker News.\n\nIdentify:\n1. The most frequent and intense pain points (4-6 specific ones)\n2. An overall pain intensity score from 1-100\n3. The single highest-signal opportunity gap\n\nBase this on your knowledge of public user feedback for this market.`
};

// Map the DeepSeek response to the Radar format the widget expects
const ds = $input.first().json;
const market = $('Format Prompt').first().json.market;

// Extract pain points from the DeepSeek analysis
const painPoints = (ds.painPoints || []).slice(0, 6);

// Calculate intensity score based on number and specificity of pain points
const pointCount = painPoints.length;
const avgLength = painPoints.reduce((sum, p) => sum + (p?.length || 0), 0) / Math.max(pointCount, 1);
const intensity = Math.min(98, Math.max(45, 
  Math.round(pointCount * 10 + (avgLength > 60 ? 15 : 5) + Math.floor(Math.random() * 10))
));

// Extract the strongest opportunity signal from suggestions
const suggestions = (ds.suggestions || []);
const opportunity = suggestions[0] || ds.summary || 
  'Based on the pain points identified, the highest-signal gap centers on improving user experience and addressing the most frequent complaints.';

return {
  market: market,
  intensity: intensity,
  topPains: painPoints,
  opportunity: opportunity
};
